# E2-Skeptic three-route assess for S49-T1-A-E2
def assess(record: dict) -> str:
    required = {'branch_count', 'known_steps', 'tool_choice_uncertain', 'baseline_success', 'case_id', 'agent_success'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (not record["known_steps"] or record["agent_success"] > record["baseline_success"])
    except Exception:
        return 'KEEP_DETERMINISTIC_WORKFLOW'
    return 'PASS' if ok else 'KEEP_DETERMINISTIC_WORKFLOW'

record = {"case_id": "CASO-AYA-049-1A", **{"known_steps":True,"branch_count":2,"tool_choice_uncertain":False,"baseline_success":0.96,"agent_success":0.9}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'agent_success'}
print(assess(valid), assess(invalid), assess(incomplete))

